211			}, p)
212		}
213	
214		var reader io.Reader
215	
216		filename, err := getModelfileName(cmd)
217		if os.IsNotExist(err) {
218			if filename == "" {
219				// No Modelfile found - check if current directory is an image gen model
220				if create.IsTensorModelDir(".") {
221					if !isLocalhost() {
222						return errors.New("remote safetensor model creation not yet supported")
223					}
