225					return xcreateclient.CreateModel(xcreateclient.CreateOptions{
226						ModelName: modelName,
227						ModelDir:  ".",
228						Quantize:  quantize,
229					}, p)
230				}
231				reader = strings.NewReader("FROM .\n")
232			} else {
233				return errModelfileNotFound
234			}
235		} else if err != nil {
236			return err
237		} else {
238			f, err := os.Open(filename)
239			if err != nil {
240				return err
241			}
242	
243			reader = f
244			defer f.Close()
245		}
246	
247		modelfile, err := parser.ParseFile(reader)
248		if err != nil {
249			return err
250		}
251	
252		status := "gathering model components"
253		spinner := progress.NewSpinner(status)
254		p.Add(status, spinner)
255	
256		req, err := modelfile.CreateRequest(filepath.Dir(filename))
257		if err != nil {
258			return err
259		}
260		spinner.Stop()
261	
262		req.Model = modelName
263		quantize, _ := cmd.Flags().GetString("quantize")
264		if quantize != "" {
265			req.Quantize = quantize
266		}
267	
268		client, err := api.ClientFromEnvironment()
269		if err != nil {
270			return err
271		}
272	
273		var g errgroup.Group
274		g.SetLimit(max(runtime.GOMAXPROCS(0)-1, 1))
275	
276		files := syncmap.NewSyncMap[string, string]()
277		for f, digest := range req.Files {
278			g.Go(func() error {
279				if _, err := createBlob(cmd, client, f, digest, p); err != nil {
280					return err
281				}
282	
283				// TODO: this is incorrect since the file might be in a subdirectory
284				//       instead this should take the path relative to the model directory
285				//       but the current implementation does not allow this
286				files.Store(filepath.Base(f), digest)
287				return nil
288			})
289		}
290	
291		adapters := syncmap.NewSyncMap[string, string]()
292		for f, digest := range req.Adapters {
293			g.Go(func() error {
294				if _, err := createBlob(cmd, client, f, digest, p); err != nil {
295					return err
296				}
297	
298				// TODO: same here
299				adapters.Store(filepath.Base(f), digest)
300				return nil
301			})
302		}
303	
304		if err := g.Wait(); err != nil {
305			return err
306		}
307	
308		req.Files = files.Items()
309		req.Adapters = adapters.Items()
310	
311		bars := make(map[string]*progress.Bar)
312		fn := func(resp api.ProgressResponse) error {
313			if resp.Digest != "" {
314				bar, ok := bars[resp.Digest]
315				if !ok {
316					msg := resp.Status
317					if msg == "" {
318						msg = fmt.Sprintf("pulling %s...", resp.Digest[7:19])
319					}
320					bar = progress.NewBar(msg, resp.Total, resp.Completed)
321					bars[resp.Digest] = bar
322					p.Add(resp.Digest, bar)
323				}
324	
325				bar.Set(resp.Completed)
326			} else if status != resp.Status {
327				spinner.Stop()
328	
329				status = resp.Status
330				spinner = progress.NewSpinner(status)
331				p.Add(status, spinner)
332			}
333	
334			return nil
335		}
336	
337		if err := client.Create(cmd.Context(), req, fn); err != nil {
338			if strings.Contains(err.Error(), "path or Modelfile are required") {
339				return fmt.Errorf("the ollama server must be updated to use `ollama create` with this client")
340			}
341			return err
342		}
343	
344		return nil
345	}
